private void configureWindow(WebWindow web) {

        if (m_fullscreen) {
            // We need to store the previous width and height values
            m_width = web.width();
            m_height = web.height();
            web.showFullScreen();
        } else {
            web.showNormal();
            if (! m_resizable) {
