    {
        table[bucketIndex] = new Entry<K,V>(hash, key, value, table[bucketIndex]);
        if (!auto_commit)
            table[bucketIndex].setStatus(Entry.ADDED, getCurrentThreadId());
        if (size++ >= threshold)
            resize(2 * table.length);
    }

